UPDATE ACCOUNT_TBL
SET balance = balance - #{amount}
WHERE account_number = #{accountNumber}
  AND balance >= #{amount}

UPDATE DEPOSIT_ACCOUNT_TBL
SET balance = balance + #{amount}
WHERE account_number = #{accountNumber}

UPDATE SAVINGS_ACCOUNT_TBL
SET balance = balance + #{amount}
WHERE account_number = #{accountNumber}
